using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("/tmp/sv-8b011a9717984a09a0b992cef031411e/build.binlog");

// Look for all source file references in the compile items
build.VisitAllChildren<Item>(item => {
    if (item.Text != null && item.Text.Contains("UserService"))
        Console.WriteLine($"Item: {item.Name} = {item.Text}");
});

// Look for all messages containing the error context  
build.VisitAllChildren<Message>(m => {
    if (m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("UserService")))
        Console.WriteLine($"Msg: {m.Text.Substring(0, Math.Min(200, m.Text.Length))}");
});

// Look for CscCommandLineArgs or similar
build.VisitAllChildren<Task>(t => {
    if (t.Name == "Csc") {
        var proj = "";
        var node = t.Parent;
        while (node != null) {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"\nCsc task in {proj}:");
        // look at command line args
        if (t.CommandLineArguments != null)
            Console.WriteLine($"  Args (first 500): {t.CommandLineArguments.Substring(0, Math.Min(500, t.CommandLineArguments.Length))}");
    }
});
EOF
